class FenwickTree {
    private size: number;
    private tree: number[];

    constructor(size: number) {
        this.size = size;
        this.tree = new Array(size + 1).fill(0);
    }

    update(index: number, delta: number): void {
        while (index <= this.size) {
            this.tree[index] += delta;
            index += index & -index;
        }
    }

    query(index: number): number {
        let res = 0;
        while (index > 0) {
            res += this.tree[index];
            index -= index & -index;
        }
        return res;
    }

    rangeQuery(l: number, r: number): number {
        return this.query(r) - this.query(l - 1);
    }
}

function countSetBits(x: number): number {
    let count = 0;
    while (x) {
        x &= x - 1;
        count++;
    }
    return count;
}

function getDepth(x: number): number {
    let current = x;
    let depth = 0;
    while (current !== 1) {
        current = countSetBits(current);
        depth++;
    }
    return depth;
}

function solve(nums: number[], queries: number[][]): number[] {
    const n = nums.length;
    const depths: number[] = [];
    for (const x of nums) {
        depths.push(getDepth(x));
    }

    const fenwickTrees: FenwickTree[] = [];
    for (let k = 0; k <= 5; k++) {
        fenwickTrees.push(new FenwickTree(n));
    }

    for (let i = 0; i < n; i++) {
        const d = depths[i];
        if (d <= 5) {
            fenwickTrees[d].update(i + 1, 1);
        }
    }

    const answer: number[] = [];
    for (const query of queries) {
        if (query[0] === 1) {
            const [_, l, r, k] = query;
            if (k > 5) {
                answer.push(0);
                continue;
            }
            const ft = fenwickTrees[k];
            const count = ft.rangeQuery(l + 1, r + 1);
            answer.push(count);
        } else {
            const [_, idx, val] = query;
            const oldVal = nums[idx];
            const oldDepth = depths[idx];
            fenwickTrees[oldDepth].update(idx + 1, -1);
            nums[idx] = val;
            const newDepth = getDepth(val);
            fenwickTrees[newDepth].update(idx + 1, 1);
            depths[idx] = newDepth;
        }
    }

    return answer;
}
